// ─── Helpers ─────────────────────────────────────────────────────────────────

function fmtDatePH(iso: string): string {
  if (!iso) return '—';
  const d = new Date(iso + (iso.length === 10 ? 'T00:00' : ''));
  return d.toLocaleDateString('en-PH', { month: 'short', day: 'numeric', year: 'numeric' });
}

function fmtTime(hhmm: string): string {
  if (!hhmm) return '';
  const [h, m] = hhmm.split(':').map(Number);
  const ampm = h >= 12 ? 'PM' : 'AM';
  const hh = h % 12 || 12;
  return `${hh}:${String(m).padStart(2, '0')} ${ampm}`;
}

function toDateStr(y: number, m: number, d: number): string {
  return `${y}-${String(m + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
}

function todayStr(): string {
  return new Date().toISOString().split('T')[0];
}

function relativeDayLabel(dateStr: string, t: (k: string, o?: object) => string): string {
  const today = todayStr();
  const d = new Date();
  d.setDate(d.getDate() + 1);
  const tom = d.toISOString().split('T')[0];
  if (dateStr === today) return t('calendar.today');
  if (dateStr === tom)   return t('calendar.tomorrow');
  const diff = Math.round((new Date(dateStr).getTime() - new Date(today).getTime()) / 86400000);
  if (diff > 0) return t('calendar.in_x_days', { days: diff });
  return fmtDatePH(dateStr);
}

