// ─── Monthly Calendar Grid ────────────────────────────────────────────────────

interface MonthGridProps {
  year: number; month: number;
  selectedDay: number | null;
  onDayPress: (day: number) => void;
  dotMap: Map<number, ReminderCategory[]>;
  onPrev: () => void; onNext: () => void;
}

function MonthGrid({ year, month, selectedDay, onDayPress, dotMap, onPrev, onNext }: MonthGridProps) {
  const today       = new Date();
  const todayY      = today.getFullYear();
  const todayM      = today.getMonth();
  const todayD      = today.getDate();

  const daysInMonth   = new Date(year, month + 1, 0).getDate();
  const firstWeekday  = new Date(year, month, 1).getDay(); // 0=Sun
  const totalCells    = Math.ceil((daysInMonth + firstWeekday) / 7) * 7;

  return (
    <View style={mg.card}>
      {/* Month navigator */}
      <View style={mg.navRow}>
        <TouchableOpacity onPress={onPrev} style={mg.navBtn} activeOpacity={0.7}>
          <Text style={mg.navArrow}>‹</Text>
        </TouchableOpacity>
        <Text style={mg.monthLabel}>{MONTH_NAMES[month]} {year}</Text>
        <TouchableOpacity onPress={onNext} style={mg.navBtn} activeOpacity={0.7}>
          <Text style={mg.navArrow}>›</Text>
        </TouchableOpacity>
      </View>

      {/* Day header */}
      <View style={mg.dayHeaderRow}>
        {DAY_LABELS.map((d, i) => (
          <Text key={i} style={[mg.dayHeader, (i === 0 || i === 6) ? { color: PINK + 'CC' } : {}]}>{d}</Text>
        ))}
      </View>

      {/* Grid */}
      <View style={mg.grid}>
        {Array.from({ length: totalCells }, (_, i) => {
          const dayNum = i - firstWeekday + 1;
          const isCurrentMonth = dayNum >= 1 && dayNum <= daysInMonth;
          const isToday  = isCurrentMonth && year === todayY && month === todayM && dayNum === todayD;
          const isSelect = isCurrentMonth && dayNum === selectedDay;
          const cats     = isCurrentMonth ? (dotMap.get(dayNum) ?? []) : [];

          return (
            <TouchableOpacity
              key={i}
              style={[mg.cell, isToday && mg.cellToday, isSelect && mg.cellSelected]}
              onPress={() => { if (isCurrentMonth) onDayPress(dayNum); }}
              activeOpacity={isCurrentMonth ? 0.7 : 1}
            >
              <Text style={[
                mg.cellNum,
                !isCurrentMonth && mg.cellNumFaded,
                isToday  && mg.cellNumToday,
                isSelect && mg.cellNumSelected,
              ]}>
                {isCurrentMonth ? dayNum : ''}
              </Text>
              {cats.length > 0 && <EventDots cats={cats} />}
            </TouchableOpacity>
          );
        })}
      </View>
    </View>
  );
}

