// ─── Notification Settings Panel ──────────────────────────────────────────────

function NotifSettingsPanel({ t }: { t: (k: string) => string }) {
  const { settings, updateSettings } = useReminderStore();
  const [exp, setExp] = useState(false);

  return (
    <View style={ns.card}>
      <TouchableOpacity style={ns.header} onPress={() => setExp(e => !e)} activeOpacity={0.8}>
        <Text style={ns.title}>{t('calendar.settings_title')}</Text>
        <Text style={{ fontSize: 16, color: GRAY }}>{exp ? '▲' : '▼'}</Text>
      </TouchableOpacity>
      {exp && (
        <View style={ns.body}>
          <View style={ns.row}>
            <Text style={ns.rowLabel}>{t('calendar.settings_master')}</Text>
            <Switch value={settings.masterEnabled} onValueChange={v => updateSettings({ masterEnabled: v })}
              trackColor={{ false: '#DDD', true: PINK }} thumbColor="#fff" />
          </View>
          {[
            { key: 'vaccineReminders',    i18n: 'calendar.settings_vaccine' },
            { key: 'checkupReminders',    i18n: 'calendar.settings_checkup' },
            { key: 'feedingReminders',    i18n: 'calendar.settings_feeding' },
            { key: 'medicationReminders', i18n: 'calendar.settings_medication' },
            { key: 'customReminders',     i18n: 'calendar.settings_custom' },
          ].map(({ key, i18n }) => (
            <View key={key} style={[ns.row, { opacity: settings.masterEnabled ? 1 : 0.4 }]}>
              <Text style={ns.rowLabel}>{t(i18n)}</Text>
              <Switch value={(settings as any)[key]} onValueChange={v => updateSettings({ [key]: v })}
                trackColor={{ false: '#DDD', true: PINK }} disabled={!settings.masterEnabled} thumbColor="#fff" />
            </View>
          ))}
          <View style={[ns.row, { marginTop: 8 }]}>
            <Text style={ns.rowLabel}>{t('calendar.settings_quiet')}</Text>
            <Switch value={settings.quietHoursEnabled} onValueChange={v => updateSettings({ quietHoursEnabled: v })}
              trackColor={{ false: '#DDD', true: PINK }} thumbColor="#fff" />
          </View>
          {settings.quietHoursEnabled && (
            <View style={{ flexDirection: 'row', gap: 12, marginTop: 8 }}>
              <View style={{ flex: 1 }}>
                <Text style={[ns.rowLabel, { marginBottom: 4 }]}>{t('calendar.settings_quiet_from')}</Text>
                <TextInput style={ns.timeInput} value={settings.quietHoursStart}
                  onChangeText={v => updateSettings({ quietHoursStart: v })} placeholder="22:00" placeholderTextColor="#BBB" />
              </View>
              <View style={{ flex: 1 }}>
                <Text style={[ns.rowLabel, { marginBottom: 4 }]}>{t('calendar.settings_quiet_to')}</Text>
                <TextInput style={ns.timeInput} value={settings.quietHoursEnd}
                  onChangeText={v => updateSettings({ quietHoursEnd: v })} placeholder="06:00" placeholderTextColor="#BBB" />
              </View>
            </View>
          )}
        </View>
      )}
    </View>
  );
}

const ns = StyleSheet.create({
  card:      { backgroundColor: Colors.surface, borderRadius: 20, marginBottom: 16, shadowColor: Colors.shadowColor, shadowOffset: { width: 0, height: 4 }, shadowOpacity: 0.08, shadowRadius: 16, elevation: 4 },
  header:    { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', padding: 16 },
  title:     { fontSize: 14, fontWeight: '800', color: DARK },
  body:      { paddingHorizontal: 16, paddingBottom: 16 },
  row:       { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', paddingVertical: 8, borderBottomWidth: 1, borderBottomColor: '#F5F5F5' },
  rowLabel:  { fontSize: 13, color: GRAY, flex: 1 },
  timeInput: { borderWidth: 1.5, borderColor: '#E0E0E0', borderRadius: 10, paddingHorizontal: 12, paddingVertical: 8, fontSize: 14, color: DARK },
});

// ─── Day Events Bottom Sheet ──────────────────────────────────────────────────

function DayEventsSheet({
  visible, dateStr, events, onClose, onAdd, onEdit, t
}: {
  visible: boolean; dateStr: string; events: CalEvent[];
  onClose: () => void; onAdd: () => void; onEdit: (ev: CalEvent) => void;
  t: (k: string, o?: object) => string;
}) {
  return (
    <Modal visible={visible} animationType="slide" transparent onRequestClose={onClose}>
      <TouchableOpacity style={ds.overlay} onPress={onClose} activeOpacity={1}>
        <View style={ds.sheet}>
          <View style={ds.handle} />
          <View style={ds.sheetHeader}>
            <Text style={ds.sheetTitle}>{t('calendar.events_for_day', { date: fmtDatePH(dateStr) })}</Text>
            <TouchableOpacity onPress={onClose}><Text style={{ fontSize: 18, color: GRAY }}>✕</Text></TouchableOpacity>
          </View>
          <ScrollView style={{ maxHeight: 340 }}>
            {events.length === 0 ? (
              <View style={ds.empty}>
                <Flower2 size={32} strokeWidth={1.5} color={PINK} style={{ marginBottom: 8 }} />
                <Text style={ds.emptyTxt}>{t('calendar.no_events_for_day')}</Text>
              </View>
            ) : (
              <View style={{ paddingHorizontal: 16, paddingBottom: 8 }}>
                {events.map(ev => (
                  <EventCard key={ev.id} ev={ev} onPress={() => {
                    if (ev.source === 'reminder' && ev.reminderId) onEdit(ev);
                  }} />
                ))}
              </View>
            )}
          </ScrollView>
          <TouchableOpacity onPress={onAdd} activeOpacity={0.85} style={{ padding: 16 }}>
            <LinearGradient colors={[Colors.primary, Colors.primaryLight]} style={ds.addBtn}>
              <Text style={ds.addTxt}>{t('calendar.add_event_for_day')}</Text>
            </LinearGradient>
          </TouchableOpacity>
        </View>
      </TouchableOpacity>
    </Modal>
  );
}

const ds = StyleSheet.create({
  overlay:     { flex: 1, backgroundColor: 'rgba(0,0,0,0.35)', justifyContent: 'flex-end' },
  sheet:       { backgroundColor: Colors.background, borderTopLeftRadius: 28, borderTopRightRadius: 28, paddingTop: 12, minHeight: 260 },
  handle:      { width: 48, height: 5, backgroundColor: '#DDD', borderRadius: 3, alignSelf: 'center', marginBottom: 12 },
  sheetHeader: { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', paddingHorizontal: 20, marginBottom: 12 },
  sheetTitle:  { fontSize: 15, fontWeight: '800', color: DARK, flex: 1 },
  empty:       { alignItems: 'center', paddingVertical: 28 },
  emptyTxt:    { fontSize: 14, color: GRAY, fontWeight: '600' },
  addBtn:      { borderRadius: 14, height: 52, alignItems: 'center', justifyContent: 'center' },
  addTxt:      { color: Colors.white, fontSize: 15, fontWeight: '800' },
});

// ─── Main Calendar Screen ─────────────────────────────────────────────────────

export default function CalendarScreen() {
  const { t: tRaw }     = useTranslation();
  // Cast to simple signature so sub-components accept it without TS errors
  const t = tRaw as (k: string, o?: object) => string;
  const { activeChild } = useChildStore();
  const reminderStore   = useReminderStore();
  const vaccineStore    = useVaccineStore();

  const today = new Date();
  const [isLoading,       setIsLoading]       = useState(true);
  const [viewYear,  setViewYear]  = useState(today.getFullYear());
  const [viewMonth, setViewMonth] = useState(today.getMonth());
  const [selDay,    setSelDay]    = useState<number | null>(null);
  const [modalVisible,    setModalVisible]    = useState(false);
  const [editingReminder, setEditingReminder] = useState<Reminder | null>(null);
  const [presetDate,      setPresetDate]      = useState<string | undefined>(undefined);
  const [daySheetVisible, setDaySheetVisible] = useState(false);
  const [filterCat, setFilterCat] = useState<ReminderCategory | 'all'>('all');

  // ── Mount-time loading spinner ──────────────────────────────────────────────
  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 300);
    return () => clearTimeout(timer);
  }, []);

  // ── Auto-generate PPS + GP on load ─────────────────────────────────────────
  useEffect(() => {
    if (!activeChild?.id || !activeChild.birthday) return;
    const nickname = getChildDisplayName(activeChild);
    reminderStore.autoGeneratePPS(activeChild.id, activeChild.birthday, nickname);
    reminderStore.autoGenerateGP(activeChild.id, today.getFullYear());
  }, [activeChild?.id]);

  // ── Build unified CalEvent list ─────────────────────────────────────────────
  const allEvents = useMemo<CalEvent[]>(() => {
    if (!activeChild?.id) return [];

    const remEvents: CalEvent[] = reminderStore.reminders
      .filter(r => r.childId === activeChild.id && r.isActive)
      .map(r => ({
        id: r.id, title: r.title,
        date: r.scheduledAt.split('T')[0],
        time: r.allDay ? undefined : r.scheduledAt.split('T')[1]?.substring(0, 5),
        category: r.category, allDay: r.allDay,
        notes: r.notes || undefined,
        source: 'reminder' as const, reminderId: r.id,
        isAutoGenerated: r.isAutoGenerated,
      }));

    const vaxEvents: CalEvent[] = vaccineStore.getRecords(activeChild.id)
      .filter(r => r.reminderEnabled && r.reminderDate && r.status !== 'given')
      .map(r => ({
        id: 'vax-' + r.id,
        title: `${r.nameEN} reminder`,
        date: r.reminderDate as string,   // safe: filtered above
        time: '09:00',
        category: 'vaccine' as ReminderCategory,
        allDay: false,
        notes: t('calendar.vaccine_reminder_note'),
        source: 'vaccine' as const,
        isAutoGenerated: true,
      }));

    return [...remEvents, ...vaxEvents]
      .sort((a, b) => a.date.localeCompare(b.date) || (a.time ?? '').localeCompare(b.time ?? ''));
  }, [reminderStore.reminders, activeChild?.id, vaccineStore.records]);

  const filteredEvents = useMemo(() =>
    filterCat === 'all' ? allEvents : allEvents.filter(e => e.category === filterCat),
    [allEvents, filterCat]);

  // ── Dot map for calendar ────────────────────────────────────────────────────
  const dotMap = useMemo(() => {
    const map = new Map<number, ReminderCategory[]>();
    for (const ev of filteredEvents) {
      const d = new Date(ev.date);
      if (d.getFullYear() === viewYear && d.getMonth() === viewMonth) {
        const day = d.getDate();
        if (!map.has(day)) map.set(day, []);
        const cats = map.get(day)!;
        if (!cats.includes(ev.category)) cats.push(ev.category);
      }
    }
    return map;
  }, [filteredEvents, viewYear, viewMonth]);

  // ── Selected day events ─────────────────────────────────────────────────────
  const selectedDateStr = selDay != null ? toDateStr(viewYear, viewMonth, selDay) : '';
  const selectedDayEvents = useMemo(() =>
    selDay != null ? filteredEvents.filter(e => e.date === selectedDateStr) : [],
    [filteredEvents, selectedDateStr]);

  // ── Upcoming events (60 days) ───────────────────────────────────────────────
  const upcomingEvents = useMemo(() => {
    const now = new Date(); now.setHours(0,0,0,0);
    const end = new Date(now); end.setDate(end.getDate() + 60);
    return filteredEvents.filter(e => {
      const d = new Date(e.date); return d >= now && d <= end;
    });
  }, [filteredEvents]);

  // ── Month nav ───────────────────────────────────────────────────────────────
  const prevMonth = () => {
    if (viewMonth === 0) { setViewYear(y => y-1); setViewMonth(11); }
    else setViewMonth(m => m-1);
    setSelDay(null);
  };
  const nextMonth = () => {
    if (viewMonth === 11) { setViewYear(y => y+1); setViewMonth(0); }
    else setViewMonth(m => m+1);
    setSelDay(null);
  };

  // ── Modal handlers ──────────────────────────────────────────────────────────
  const openAdd = (date?: string) => {
    setEditingReminder(null);
    setPresetDate(date);
    setDaySheetVisible(false);
    setModalVisible(true);
  };
  const openEdit = (ev: CalEvent) => {
    if (ev.source === 'vaccine' || !ev.reminderId) return;
    const rem = reminderStore.reminders.find(r => r.id === ev.reminderId) ?? null;
    setEditingReminder(rem);
    setDaySheetVisible(false);
    setModalVisible(true);
  };
  const handleSave = (form: ReminderForm) => {
    if (!activeChild?.id) return;
    const scheduledAt = (form.allDay ? form.date + 'T00:00' : form.date + 'T' + (form.time || '09:00'));
    if (editingReminder) {
      reminderStore.updateReminder(editingReminder.id, {
        title: form.title, category: form.category, scheduledAt,
        allDay: form.allDay, repeatType: form.repeatType,
        notifyMinutesBefore: form.notifyMinutesBefore, notes: form.notes,
      });
    } else {
      reminderStore.addReminder({
        childId: activeChild.id, title: form.title, category: form.category,
        scheduledAt, allDay: form.allDay, repeatType: form.repeatType,
        notifyMinutesBefore: form.notifyMinutesBefore, notes: form.notes,
        isActive: true, isAutoGenerated: false,
      });
    }
    setModalVisible(false);
    setEditingReminder(null);
  };

  // ── Loading guard ────────────────────────────────────────────────────────────
  if (isLoading) {
    return (
      <View style={{ flex: 1, backgroundColor: BG }}>
        {/* Calendar placeholder */}
        <View style={{ margin: 16, borderRadius: 20, backgroundColor: '#fff', padding: 16,
          shadowColor: Colors.shadowColor, shadowOffset: { width: 0, height: 4 },
          shadowOpacity: 0.08, shadowRadius: 16, elevation: 4 }}>
          <View style={{ height: 24, width: '40%', borderRadius: 8, backgroundColor: Colors.divider, marginBottom: 14 }} />
          <View style={{ flexDirection: 'row', justifyContent: 'space-between' }}>
            {Array.from({ length: 7 }).map((_, i) => (
              <View key={i} style={{ width: 32, height: 32, borderRadius: 16, backgroundColor: Colors.divider }} />
            ))}
          </View>
          <View style={{ marginTop: 12, gap: 8 }}>
            {Array.from({ length: 5 }).map((_, i) => (
              <View key={i} style={{ flexDirection: 'row', gap: 6 }}>
                {Array.from({ length: 7 }).map((_, j) => (
                  <View key={j} style={{ width: 32, height: 32, borderRadius: 16, backgroundColor: Colors.divider, opacity: 0.5 + (j % 3) * 0.2 }} />
                ))}
              </View>
            ))}
          </View>
        </View>
        {/* Event rows */}
        <SkeletonList count={4} variant="row" />
      </View>
    );
  }

  // ── No child guard ──────────────────────────────────────────────────────────
  if (!activeChild) {
    return (
      <View style={{ flex: 1, backgroundColor: BG, alignItems: 'center', justifyContent: 'center', padding: 32 }}>
        <CalendarIcon size={48} strokeWidth={1.5} color={PINK} style={{ marginBottom: 16 }} />
        <Text style={{ fontSize: 18, fontWeight: '800', color: DARK, textAlign: 'center', marginBottom: 8 }}>
          {t('calendar.empty_state_title')}
        </Text>
        <Text style={{ fontSize: 14, color: GRAY, textAlign: 'center', lineHeight: 22 }}>
          {t('calendar.empty_state_sub')}
        </Text>
      </View>
    );
  }

  // ── Group upcoming by date label ────────────────────────────────────────────
  const upcomingGrouped: { label: string; date: string; events: CalEvent[] }[] = [];
  const seenDates = new Set<string>();
  for (const ev of upcomingEvents) {
    if (!seenDates.has(ev.date)) {
      seenDates.add(ev.date);
      upcomingGrouped.push({
        label: relativeDayLabel(ev.date, t), date: ev.date,
        events: upcomingEvents.filter(e => e.date === ev.date),
      });
    }
  }

  return (
    <View style={{ flex: 1, backgroundColor: BG }}>
      <ScrollView contentContainerStyle={sc.content} showsVerticalScrollIndicator={false}>

        {/* Weekly summary */}
        <WeeklySummaryBar events={allEvents} t={t} />

        {/* Monthly calendar grid */}
        <MonthGrid
          year={viewYear} month={viewMonth} selectedDay={selDay}
          onDayPress={d => { setSelDay(d); setDaySheetVisible(true); }}
          dotMap={dotMap} onPrev={prevMonth} onNext={nextMonth}
        />

        {/* Category legend */}
        <Text style={sc.sectionTitle}>{t('calendar.legend_title')}</Text>
        <CategoryLegend t={t} />

        {/* Category filter chips */}
        <ScrollView horizontal showsHorizontalScrollIndicator={false} style={{ marginBottom: 16 }}>
          <View style={{ flexDirection: 'row', gap: 8, paddingHorizontal: 2, paddingBottom: 4 }}>
            {(['all', ...ALL_CATS] as (ReminderCategory | 'all')[]).map(cat => {
              const sel = filterCat === cat;
              const cfg = cat === 'all' ? { color: PINK, bg: Colors.softPink, icon: <CalendarDays size={13} strokeWidth={1.5} color={PINK} /> } : CAT[cat];
              return (
                <TouchableOpacity key={cat}
                  style={[fc.chip, { backgroundColor: sel ? cfg.color : Colors.white, borderColor: cfg.color }]}
                  onPress={() => setFilterCat(cat)} activeOpacity={0.8}>
                  {cfg.icon}
                  <Text style={[fc.label, { color: sel ? Colors.white : cfg.color }]}>
                    {cat === 'all' ? t('calendar.filter_all') : t(`calendar.${cat}`)}
                  </Text>
                </TouchableOpacity>
              );
            })}
          </View>
        </ScrollView>

        {/* Upcoming events */}
        <View style={sc.sectionRow}>
          <Text style={sc.sectionTitle}>{t('calendar.upcoming_section')}</Text>
          <Text style={sc.sectionSub}>{t('calendar.upcoming_subtitle', { days: 60 })}</Text>
        </View>

        {upcomingGrouped.length === 0 ? (
          <View style={sc.emptyBox}>
            <Flower2 size={36} strokeWidth={1.5} color={PINK} style={{ marginBottom: 8 }} />
            <Text style={sc.emptyTxt}>{t('calendar.no_upcoming')}</Text>
          </View>
        ) : (
          upcomingGrouped.map(grp => (
            <View key={grp.date} style={{ marginBottom: 8 }}>
              <View style={sc.dateLabelRow}>
                <Text style={sc.dateLabel}>{grp.label}</Text>
                <Text style={sc.dateNum}>{fmtDatePH(grp.date)}</Text>
              </View>
              {grp.events.map(ev => (
                <EventCard key={ev.id} ev={ev}
                  onPress={() => { if (ev.source === 'reminder' && ev.reminderId) openEdit(ev); }} />
              ))}
            </View>
          ))
        )}

        {/* Notification settings */}
        <NotifSettingsPanel t={t} />

        {/* Find BHS / RHU */}
        <TouchableOpacity activeOpacity={0.85}>
          <LinearGradient colors={[Colors.blue, '#4A9DE8']} style={sc.bhsBtn}>
            <Text style={sc.bhsTxt}>{t('calendar.find_bhs')}</Text>
          </LinearGradient>
        </TouchableOpacity>

        <View style={{ height: 24 }} />
      </ScrollView>

      {/* FAB */}
      <TouchableOpacity style={sc.fab} onPress={() => openAdd()} activeOpacity={0.85}>
        <LinearGradient colors={['#F06292', Colors.primaryPink]} style={sc.fabGrad}>
          <Text style={{ fontSize: 28, color: Colors.white, lineHeight: 32 }}>+</Text>
        </LinearGradient>
      </TouchableOpacity>

      {/* Day sheet */}
      <DayEventsSheet
        visible={daySheetVisible && selDay != null}
        dateStr={selectedDateStr} events={selectedDayEvents}
        onClose={() => setDaySheetVisible(false)}
        onAdd={() => openAdd(selectedDateStr)}
        onEdit={openEdit} t={t}
      />

      {/* Add/Edit modal */}
      <ReminderModal
        visible={modalVisible} editing={editingReminder}
        childId={activeChild.id} presetDate={presetDate}
        onClose={() => { setModalVisible(false); setEditingReminder(null); }}
        onSave={handleSave}
        onDelete={id => { reminderStore.deleteReminder(id); }}
        t={t}
      />
    </View>
  );
}

const fc = StyleSheet.create({
  chip:  { flexDirection: 'row', alignItems: 'center', gap: 4, borderRadius: 20, paddingHorizontal: 12, paddingVertical: 7, borderWidth: 1.5 },
  label: { fontSize: 11, fontWeight: '700' },
});
const sc = StyleSheet.create({
  content:      { padding: 16, paddingBottom: 100 },
  sectionRow:   { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 },
  sectionTitle: { fontSize: 13, fontWeight: '800', color: PINK, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 8 },
  sectionSub:   { fontSize: 11, color: GRAY },
  dateLabelRow: { flexDirection: 'row', alignItems: 'center', gap: 8, marginBottom: 6 },
  dateLabel:    { fontSize: 12, fontWeight: '800', color: PINK, backgroundColor: Colors.softPink, borderRadius: 8, paddingHorizontal: 10, paddingVertical: 4 },
  dateNum:      { fontSize: 11, color: GRAY },
  emptyBox:     { alignItems: 'center', backgroundColor: Colors.white, borderRadius: 18, padding: 32, marginBottom: 16 },
  emptyTxt:     { fontSize: 14, color: GRAY, fontWeight: '600' },
  bhsBtn:       { borderRadius: 16, paddingVertical: 16, alignItems: 'center', marginBottom: 12, shadowColor: Colors.blue, shadowOpacity: 0.25, shadowRadius: 8, elevation: 4 },
  bhsTxt:       { color: Colors.white, fontSize: 15, fontWeight: '800' },
  fab:          { position: 'absolute', bottom: 88, right: 20, shadowColor: PINK, shadowOpacity: 0.4, shadowRadius: 12, elevation: 8 },
  fabGrad:      { width: 58, height: 58, borderRadius: 29, alignItems: 'center', justifyContent: 'center' },
});
